import jwt
import json
from datetime import datetime, timezone
from typing import Optional, Union


def decode_jwt_unverified(token: str) -> dict:
    """
    Decode a JWT token WITHOUT verifying the signature.
    Useful for debugging and inspecting token contents.
    
    WARNING: Do not use this for authentication/authorization decisions.
    """
    # Decode header without verification
    header = jwt.get_unverified_header(token)
    
    # Decode payload without verification
    payload = jwt.decode(token, options={"verify_signature": False})
    
    return {
        "header": header,
        "payload": payload
    }


def decode_jwt_verified(token: str, secret: str, algorithms: Optional[list] = None,
                        audience: Optional[str] = None, issuer: Optional[str] = None) -> dict:
    """
    Decode and verify a JWT token with the given secret/key.
    
    Args:
        token: The JWT token string
        secret: The secret key or public key for verification
        algorithms: List of allowed algorithms (default: ["HS256"])
        audience: Expected audience claim
        issuer: Expected issuer claim
    
    Returns:
        Dictionary with header, payload, and verification status
    """
    if algorithms is None:
        algorithms = ["HS256"]
    
    decode_options = {}
    if audience:
        decode_options["audience"] = audience
    if issuer:
        decode_options["issuer"] = issuer
    
    header = jwt.get_unverified_header(token)
    payload = jwt.decode(token, secret, algorithms=algorithms, **decode_options)
    
    return {
        "header": header,
        "payload": payload,
        "verified": True
    }


def inspect_jwt(token: str, secret: Optional[str] = None,
                algorithms: Optional[list] = None) -> dict:
    """
    Full inspection of a JWT token for debugging purposes.
    Provides decoded contents, expiration info, and optional verification.
    
    Args:
        token: The JWT token string
        secret: Optional secret for signature verification
        algorithms: Optional list of allowed algorithms
    
    Returns:
        Detailed inspection report as a dictionary
    """
    report = {
        "token_preview": f"{token[:20]}...{token[-20:]}" if len(token) > 40 else token,
        "token_length": len(token),
        "num_segments": len(token.split(".")),
        "header": None,
        "payload": None,
        "claims_analysis": {},
        "signature_verified": None,
        "verification_error": None,
        "warnings": []
    }
    
    # Check basic structure
    segments = token.split(".")
    if len(segments) != 3:
        report["warnings"].append(f"Expected 3 segments, found {len(segments)}")
        return report
    
    # Decode without verification
    try:
        decoded = decode_jwt_unverified(token)
        report["header"] = decoded["header"]
        report["payload"] = decoded["payload"]
    except jwt.exceptions.DecodeError as e:
        report["warnings"].append(f"Failed to decode token: {str(e)}")
        return report
    
    payload = report["payload"]
    
    # Analyze standard claims
    now = datetime.now(timezone.utc)
    now_ts = now.timestamp()
    
    # Expiration (exp)
    if "exp" in payload:
        exp_dt = datetime.fromtimestamp(payload["exp"], tz=timezone.utc)
        is_expired = now_ts > payload["exp"]
        time_diff = payload["exp"] - now_ts
        
        report["claims_analysis"]["exp"] = {
            "value": payload["exp"],
            "datetime_utc": exp_dt.isoformat(),
            "is_expired": is_expired,
            "time_remaining_seconds": max(0, time_diff),
            "time_remaining_human": _format_timedelta(time_diff) if not is_expired else "EXPIRED"
        }
        
        if is_expired:
            report["warnings"].append(
                f"Token is EXPIRED (expired {_format_timedelta(abs(time_diff))} ago)"
            )
    else:
        report["warnings"].append("No 'exp' (expiration) claim found")
    
    # Issued at (iat)
    if "iat" in payload:
        iat_dt = datetime.fromtimestamp(payload["iat"], tz=timezone.utc)
        age = now_ts - payload["iat"]
        report["claims_analysis"]["iat"] = {
            "value": payload["iat"],
            "datetime_utc": iat_dt.isoformat(),
            "token_age_seconds": age,
            "token_age_human": _format_timedelta(age)
        }
    
    # Not before (nbf)
    if "nbf" in payload:
        nbf_dt = datetime.fromtimestamp(payload["nbf"], tz=timezone.utc)
        is_active = now_ts >= payload["nbf"]
        report["claims_analysis"]["nbf"] = {
            "value": payload["nbf"],
            "datetime_utc": nbf_dt.isoformat(),
            "is_active": is_active
        }
        if not is_active:
            report["warnings"].append(
                f"Token is NOT YET VALID (becomes valid at {nbf_dt.isoformat()})"
            )
    
    # Issuer (iss)
    if "iss" in payload:
        report["claims_analysis"]["iss"] = payload["iss"]
    
    # Subject (sub)
    if "sub" in payload:
        report["claims_analysis"]["sub"] = payload["sub"]
    
    # Audience (aud)
    if "aud" in payload:
        report["claims_analysis"]["aud"] = payload["aud"]
    
    # JWT ID (jti)
    if "jti" in payload:
        report["claims_analysis"]["jti"] = payload["jti"]
    
    # Algorithm warnings
    alg = report["header"].get("alg", "unknown")
    if alg == "none":
        report["warnings"].append("SECURITY: Algorithm is 'none' - token is unsigned!")
    elif alg in ("HS256", "HS384", "HS512"):
        report["claims_analysis"]["algorithm_type"] = "symmetric (HMAC)"
    elif alg in ("RS256", "RS384", "RS512", "ES256", "ES384", "ES512", "PS256", "PS384", "PS512"):
        report["claims_analysis"]["algorithm_type"] = "asymmetric"
    
    # Verify signature if secret provided
    if secret is not None:
        try:
            decode_jwt_verified(token, secret, algorithms=algorithms)
            report["signature_verified"] = True
        except jwt.ExpiredSignatureError:
            report["signature_verified"] = True
            report["verification_error"] = "Token signature is valid but token is expired"
        except jwt.InvalidSignatureError:
            report["signature_verified"] = False
            report["verification_error"] = "Invalid signature - secret key may be wrong"
        except jwt.InvalidAlgorithmError as e:
            report["signature_verified"] = False
            report["verification_error"] = f"Invalid algorithm: {str(e)}"
        except jwt.InvalidTokenError as e:
            report["signature_verified"] = False
            report["verification_error"] = f"Token validation failed: {str(e)}"
    
    return report


def _format_timedelta(seconds: float) -> str:
    """Format seconds into a human-readable time delta string."""
    abs_seconds = abs(seconds)
    
    if abs_seconds < 60:
        return f"{abs_seconds:.0f} seconds"
    elif abs_seconds < 3600:
        minutes = abs_seconds / 60
        return f"{minutes:.1f} minutes"
    elif abs_seconds < 86400:
        hours = abs_seconds / 3600
        return f"{hours:.1f} hours"
    else:
        days = abs_seconds / 86400
        return f"{days:.1f} days"


def create_debug_token(payload: dict, secret: str = "debug-secret",
                       algorithm: str = "HS256",
                       expiration_minutes: int = 60) -> str:
    """
    Create a JWT token for testing/debugging purposes.
    
    Args:
        payload: Dictionary of claims to include
        secret: Secret key for signing
        algorithm: Signing algorithm
        expiration_minutes: Token expiration time in minutes
    
    Returns:
        Encoded JWT token string
    """
    now = datetime.now(timezone.utc)
    
    default_claims = {
        "iat": int(now.timestamp()),
        "exp": int(now.timestamp()) + (expiration_minutes * 60),
    }
    
    # Merge defaults with provided payload (provided values take precedence)
    full_payload = {**default_claims, **payload}
    
    token = jwt.encode(full_payload, secret, algorithm=algorithm)
    return token


def pretty_print_inspection(report: dict) -> None:
    """Pretty print a JWT inspection report to the console."""
    print("=" * 60)
    print("JWT TOKEN INSPECTION REPORT")
    print("=" * 60)
    
    print(f"\nToken Preview: {report['token_preview']}")
    print(f"Token Length:  {report['token_length']} characters")
    print(f"Segments:      {report['num_segments']}")
    
    if report["header"]:
        print(f"\n--- HEADER ---")
        print(json.dumps(report["header"], indent=2))
    
    if report["payload"]:
        print(f"\n--- PAYLOAD ---")
        print(json.dumps(report["payload"], indent=2, default=str))
    
    if report["claims_analysis"]:
        print(f"\n--- CLAIMS ANALYSIS ---")
        print(json.dumps(report["claims_analysis"], indent=2, default=str))
    
    if report["signature_verified"] is not None:
        print(f"\n--- SIGNATURE VERIFICATION ---")
        status = "✅ VALID" if report["signature_verified"] else "❌ INVALID"
        print(f"Status: {status}")
        if report["verification_error"]:
            print(f"Detail: {report['verification_error']}")
    
    if report["warnings"]:
        print(f"\n--- WARNINGS ---")
        for warning in report["warnings"]:
            print(f"  ⚠️  {warning}")
    
    print("\n" + "=" * 60)


